package main

import (
    "fmt"
    "time"
)

func main() {
    // ---- Buffered channels ----
    ch := make(chan int, 3)

    // ---- Sending without blocking (until full) ----
    ch <- 1
    ch <- 2
    ch <- 3
    fmt.Println("Sent 3 values without blocking")

    // ---- Reading ----
    fmt.Println(<-ch)  // 1
    fmt.Println(<-ch)  // 2
    fmt.Println(<-ch)  // 3

    // ---- Buffer full blocks ----
    ch2 := make(chan int, 2)

    ch2 <- 1
    ch2 <- 2

    go func() {
        time.Sleep(100 * time.Millisecond)
        <-ch2
        fmt.Println("Receiver read a value")
    }()

    // This will block until someone reads
    ch2 <- 3
    fmt.Println("Sent 3 after receiver read")

    // ---- Buffer with range ----
    ch3 := make(chan int, 3)

    go func() {
        for i := 1; i <= 3; i++ {
            ch3 <- i
        }
        close(ch3)
    }()

    for v := range ch3 {
        fmt.Println("Range:", v)
    }

    // ---- Channel capacity and length ----
    ch4 := make(chan int, 5)
    fmt.Printf("len: %d, cap: %d\n", len(ch4), cap(ch4))

    ch4 <- 1
    ch4 <- 2
    fmt.Printf("len: %d, cap: %d\n", len(ch4), cap(ch4))

    <-ch4
    fmt.Printf("len: %d, cap: %d\n", len(ch4), cap(ch4))
}
